int main() {
    int arr[] = {10, 20, 30, 40, 50};
    int *p = arr;  // points to arr[0]

    cout << *p << endl;       // 10
    cout << *(p + 1) << endl; // 20  (moved 4 bytes forward)
    cout << *(p + 3) << endl; // 40

    p += 2;  // now points to arr[2]
    cout << *p << endl;       // 30

    // Pointer difference
    int *start = arr;
    int *end = arr + 4;
    cout << "Elements between: " << (end - start) << endl; // 4

