    return op(x, y);
}

// Using typedef for clarity
typedef int (*BinaryOp)(int, int);
// Or modern: using BinaryOp = int(*)(int, int);

int main() {
    // Direct function pointer
    int (*fp)(int, int) = &add;  // & is optional
    cout << fp(3, 4) << endl;    // 7

    // Callback pattern
    cout << compute(5, 3, add) << endl;      // 8
    cout << compute(5, 3, multiply) << endl; // 15

    // Modern C++: std::function
    function<int(int,int)> op = multiply;
    cout << op(6, 7) << endl;  // 42

    // Lambda as function pointer (if non-capturing)
    auto sub = [](int a, int b) -> int { return a - b; };
    cout << compute(10, 3, sub) << endl;  // 7
    return 0;
}

