    return &local;  // WARNING: dangling pointer!
}

int main() {
    // Scenario 1: Use after free
    int *p = new int(10);
    delete p;
    // *p = 20;  // UNDEFINED BEHAVIOR! p is dangling
    p = nullptr; // Good practice: nullify after delete

    // Scenario 2: Returning local address
    int *bad = dangling();
    // *bad is undefined behavior

    // Scenario 3: Wild pointer
    int *wild;    // uninitialized — contains garbage address
    // *wild = 5; // UNDEFINED BEHAVIOR!

    // Correct: always initialize
    int *safe = nullptr;
    if (safe != nullptr) {
        cout << *safe << endl;
    }
    return 0;
}

