using namespace std;

class MyClass {
public:
    MyClass() { cout << "Constructor called\n"; }
    ~MyClass() { cout << "Destructor called\n"; }
};

int main() {
    // C++ way: constructor IS called
    MyClass *obj1 = new MyClass();  // Constructor called
    delete obj1;                     // Destructor called

    // C way: constructor NOT called
    MyClass *obj2 = (MyClass*)malloc(sizeof(MyClass));
    // obj2 is uninitialized raw memory!
    free(obj2);  // Destructor NOT called

    // Arrays
    int *arr = new int[5]{1,2,3,4,5};
    delete[] arr;  // MUST use delete[], not delete

    // Placement new: construct at specific address
    char buffer[sizeof(MyClass)];
    MyClass *placed = new (buffer) MyClass();  // Construct in buffer
    placed->~MyClass();  // Must manually call destructor!
    // Do NOT delete placed — it's on the stack!

    return 0;
}

