#include <iostream>
#include <bitset>
using namespace std;

int main() {
    int n = 0b1010;  // 10

    // Set bit 0 -> 1011 (11)
    cout << bitset<4>(n | (1 << 0)) << endl;

    // Clear bit 1 -> 1000 (8)
    cout << bitset<4>(n & ~(1 << 1)) << endl;

    // Toggle bit 3 -> 0010 (2)
    cout << bitset<4>(n ^ (1 << 3)) << endl;

    // Check if bit 1 is set
    cout << "Bit 1: " << ((n >> 1) & 1) << endl; // 1

    // Power of 2?
    int p = 16;
    cout << p << " is power of 2: " << (p > 0 && (p & (p-1)) == 0) << endl;

    // Count set bits (Brian Kernighan's algorithm)
    int count = 0;
    int x = 0b1011011;
    while (x) {
        x &= (x - 1);  // clears lowest set bit
        count++;
    }
    cout << "Set bits: " << count << endl;  // 5

    // Swap without temp
    int a = 5, b = 3;
    a ^= b; b ^= a; a ^= b;
    cout << "a=" << a << " b=" << b << endl; // a=3 b=5
    return 0;
}

#include <iostream>
using namespace std;

// Permission flags (like Unix file permissions)
constexpr unsigned int READ    = 1 << 0;  // 0001
constexpr unsigned int WRITE   = 1 << 1;  // 0010
constexpr unsigned int EXECUTE = 1 << 2;  // 0100
constexpr unsigned int ADMIN   = 1 << 3;  // 1000

void printPerms(unsigned int perms) {
    if (perms & READ)    cout << "READ ";
    if (perms & WRITE)   cout << "WRITE ";
    if (perms & EXECUTE) cout << "EXECUTE ";
    if (perms & ADMIN)   cout << "ADMIN ";
    cout << endl;
}

int main() {
    unsigned int perms = 0;

    perms |= READ | WRITE;     // Grant read and write
    printPerms(perms);          // READ WRITE

    perms |= EXECUTE;          // Add execute
    printPerms(perms);          // READ WRITE EXECUTE

    perms &= ~WRITE;           // Revoke write
    printPerms(perms);          // READ EXECUTE

    perms ^= ADMIN;            // Toggle admin
    printPerms(perms);          // READ EXECUTE ADMIN
    return 0;
}

#include <iostream>
#include <cstdint>
using namespace std;

bool isLittleEndian() {
    uint32_t num = 1;
    // If least significant byte is at lowest address
    return *reinterpret_cast<uint8_t*>(&num) == 1;
}

// Manual byte swap (big-endian <-> little-endian)
uint32_t byteSwap32(uint32_t x) {
    return ((x >> 24) & 0xFF)       |
           ((x >> 8)  & 0xFF00)     |
           ((x << 8)  & 0xFF0000)   |
           ((x << 24) & 0xFF000000);
}

int main() {
    cout << "System is " << (isLittleEndian() ? "little" : "big")
         << "-endian" << endl;

    uint32_t val = 0x12345678;
    uint32_t swapped = byteSwap32(val);
    cout << hex << "Original: 0x" << val << endl;
    cout << hex << "Swapped:  0x" << swapped << endl;
    // Original: 0x12345678
    // Swapped:  0x78563412
    return 0;
}

#include <iostream>
#include <cstring>
#include <utility>
using namespace std;

class String {
    char* data_;
    size_t size_;
public:
    // Constructor
    String(const char* s = "") : size_(strlen(s)) {
        data_ = new char[size_ + 1];
        strcpy(data_, s);
        cout << "Constructed: " << data_ << "\n";
    }

    // Destructor
    ~String() {
        delete[] data_;
    }

    // Copy constructor (deep copy)
    String(const String& other) : size_(other.size_) {
        data_ = new char[size_ + 1];
        strcpy(data_, other.data_);
        cout << "Copy constructed: " << data_ << "\n";
    }

    // Move constructor (steal resources)
    String(String&& other) noexcept : data_(other.data_), size_(other.size_) {
        other.data_ = nullptr;
        other.size_ = 0;
        cout << "Move constructed\n";
    }

    // Copy assignment (copy-and-swap idiom)
    String& operator=(String other) {  // pass by value = copy
        swap(data_, other.data_);
        swap(size_, other.size_);
        return *this;
    }
    // Move assignment handled by copy assignment via pass-by-value
};

