#include <iostream>
#include <thread>
#include <mutex>
#include <condition_variable>
#include <queue>
using namespace std;

queue<int> buffer;
mutex mtx;
condition_variable cv;
bool done = false;

void producer() {
    for (int i = 0; i < 5; i++) {
        {
            lock_guard<mutex> lock(mtx);
            buffer.push(i);
            cout << "Produced: " << i << endl;
        }
        cv.notify_one();
    }
    { lock_guard<mutex> lock(mtx); done = true; }
    cv.notify_all();
}

void consumer() {
    while (true) {
        unique_lock<mutex> lock(mtx);
        cv.wait(lock, [] { return !buffer.empty() || done; });
        while (!buffer.empty()) {
            cout << "Consumed: " << buffer.front() << endl;
            buffer.pop();
        }
        if (done) break;
    }
}

int main() {
    thread p(producer), c(consumer);
    p.join(); c.join();
    return 0;
}

